        # ------------------------------------------------------------------
        risk_compression = (
            vol > self.VOL_COMPRESSION_TRIGGER
            or dd_result["p95"] > self.MAX_DRAWDOWN_THRESHOLD
            or current_regime == GlobalRegimeState.CRISIS
        )

